import React, { useState } from 'react';
import { supabase } from '../supabase';
import { useAuth } from '../context/AuthContext';
import { uid, today, fmtDate, S, DEFECT_REASONS, RETUR_REASONS } from '../utils';
import { Btn, FieldGroup, DataTable, EmptyState } from '../components/UI';

const logActivity = async (user, action, description) => {
  await supabase.from('activity_log').insert({ id: uid(), user_id: user.id, user_name: user.name, action, description });
};

export default function StockManager({ products, outlets, stockIn, stockOut, returns, currentStock, onRefresh, showToast }) {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('in');
  const [form, setForm] = useState({ product_id:'', qty:'', notes:'', date: today(), batch_code:'', expired_date:'', reason:'', out_type:'manual_defect', outlet_id:'', order_id:'', return_type:'retur_outlet' });
  const [saving, setSaving] = useState(false);
  const [summaryKat, setSummaryKat] = useState('all');
  const [summarySearch, setSummarySearch] = useState('');
  const [onlyHasStock, setOnlyHasStock] = useState(true);
  const [formKat, setFormKat] = useState('');
  const [formVariant, setFormVariant] = useState('');
  const [returKondisi, setReturKondisi] = useState(''); // 'rusak' | 'repakai'
  const [returAction, setReturAction] = useState('');   // 'same' | 'convert'
  const [convertTargetId, setConvertTargetId] = useState('');
  const [convertQty, setConvertQty] = useState('');
  // Konversi Stok state
  const [konvKat,       setKonvKat]       = useState('');
  const [konvVariant,   setKonvVariant]   = useState('');
  const [konvSrcId,     setKonvSrcId]     = useState('');
  const [konvQty,       setKonvQty]       = useState('');
  const [konvTargetId,  setKonvTargetId]  = useState('');
  const [konvManualQty, setKonvManualQty] = useState('');
  const [konvDate,      setKonvDate]      = useState(today());
  const [konvNotes,     setKonvNotes]     = useState('');
  const canEdit = user?.role === 'admin' || user?.role === 'produksi';

  const SIZE_ORDER = ['Slice','Quarter','Half','Round','Square'];
  const getVariant = name => { const m = name.match(/^(.+?)\s*-\s*(Slice|Quarter|Half|Round|Square|Loyang)$/i); return m ? m[1].trim() : name; };
  const getSizeName = name => { const m = name.match(/\s*-\s*(Slice|Quarter|Half|Round|Square|Loyang)$/i); return m ? m[1] : ''; };
  const variantsFor = kat => [...new Set(products.filter(p => !kat || p.kategori === kat).map(p => getVariant(p.name)))].sort();
  const sizesFor = variant => products.filter(p => getVariant(p.name) === variant).sort((a,b) => {
    const ai = SIZE_ORDER.findIndex(s => a.name.endsWith(s)), bi = SIZE_ORDER.findIndex(s => b.name.endsWith(s));
    return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
  });

  // Conversion rules: what sizes can a returned product be cut into?
  const getConversionTargets = (product) => {
    if (!product) return [];
    const size = getSizeName(product.name);
    const variant = getVariant(product.name);
    const kat = product.kategori;
    const sameVariant = products.filter(p => getVariant(p.name) === variant && p.id !== product.id);
    const find = s => sameVariant.find(p => getSizeName(p.name).toLowerCase() === s.toLowerCase());
    const targets = [];
    if (kat === 'Lapis Legit') {
      if (size === 'Half') {
        const qtr = find('Quarter'); if (qtr) targets.push({ product: qtr, label:'Quarter', ratio:2, isAuto:true });
        const slc = find('Slice');   if (slc) targets.push({ product: slc, label:'Slice',   ratio:null, isAuto:false });
      } else if (size === 'Quarter') {
        const slc = find('Slice');   if (slc) targets.push({ product: slc, label:'Slice',   ratio:null, isAuto:false });
      }
      // Slice, Round, Square → no conversion
    } else if (kat === 'Lapis Surabaya') {
      if (size === 'Loyang' || size === '') {
        const half = find('Half');   if (half) targets.push({ product: half, label:'Half',  ratio:2,    isAuto:true });
        const slc  = find('Slice');  if (slc)  targets.push({ product: slc,  label:'Slice', ratio:null, isAuto:false });
      } else if (size === 'Half') {
        const slc = find('Slice');   if (slc) targets.push({ product: slc,  label:'Slice',  ratio:null, isAuto:false });
      }
      // Slice → no conversion
    }
    return targets;
  };

  const KAT_LIST = ['Lapis Legit','Lapis Surabaya','Cookies','Gift Box'];

  const tabColor = { in:'#10b981', out:'#ef4444', retur:'#f59e0b', konversi:'#8b5cf6' };
  const tabLabel = { in:'Stok Masuk', out:'Keluar/Defect', retur:'Retur dari Outlet', konversi:'✂️ Konversi Stok' };

  const resetForm = () => {
    setForm({ product_id:'', qty:'', notes:'', date: today(), batch_code:'', expired_date:'', reason:'', out_type:'manual_defect', outlet_id:'', order_id:'', return_type:'retur_outlet' });
    setFormKat(''); setFormVariant('');
    setReturKondisi(''); setReturAction(''); setConvertTargetId(''); setConvertQty('');
  };

  const handleAdd = async () => {
    if (!form.product_id || !form.qty) return showToast('❌ Produk & qty wajib diisi');
    if (activeTab === 'in' && !form.batch_code) return showToast('❌ Kode batch wajib diisi');
    if (activeTab === 'out' && !form.reason) return showToast('❌ Alasan wajib diisi');
    if (activeTab === 'out' && Number(form.qty) > (currentStock[form.product_id]||0)) return showToast('❌ Stok tidak cukup');
    if (activeTab === 'retur' && !returKondisi) return showToast('❌ Pilih kondisi barang');
    if (activeTab === 'retur' && returKondisi === 'repakai' && !returAction) return showToast('❌ Pilih tindakan untuk barang');
    if (activeTab === 'retur' && returAction === 'convert' && !convertTargetId) return showToast('❌ Pilih ukuran tujuan konversi');
    if (activeTab === 'retur' && !form.reason) return showToast('❌ Alasan wajib diisi');

    setSaving(true);
    const p = products.find(x => x.id === form.product_id);
    const outletName = outlets.find(o => o.id === form.outlet_id)?.name || 'outlet';
    let error;

    if (activeTab === 'in') {
      ({ error } = await supabase.from('stock_in').insert({ id: uid(), product_id: form.product_id, qty: Number(form.qty), notes: form.notes, date: form.date, batch_code: form.batch_code, expired_date: form.expired_date || null, created_by: user.id, created_by_name: user.name }));
      if (!error) {
        await supabase.from('batches').insert({ id: uid(), batch_code: form.batch_code, product_id: form.product_id, qty_initial: Number(form.qty), expired_date: form.expired_date || null, notes: form.notes, created_by: user.id, created_by_name: user.name });
        await logActivity(user, 'stok_masuk', `Stok masuk ${form.qty} ${p?.unit} ${p?.name} — Batch: ${form.batch_code}`);
      }
    } else if (activeTab === 'out') {
      ({ error } = await supabase.from('stock_out').insert({ id: uid(), product_id: form.product_id, qty: Number(form.qty), notes: form.notes, date: form.date, reason: form.reason, out_type: form.out_type, created_by: user.id, created_by_name: user.name }));
      if (!error) await logActivity(user, 'stok_keluar', `Stok keluar ${form.qty} ${p?.unit} ${p?.name} — ${form.reason}`);
    } else {
      // RETUR logic
      if (returKondisi === 'rusak') {
        // Expired/rusak — record only, does NOT add to stock
        ({ error } = await supabase.from('returns').insert({ id: uid(), product_id: form.product_id, qty: Number(form.qty), notes: form.notes, date: form.date, outlet_id: form.outlet_id || null, reason: form.reason, return_type: 'expired_rusak', created_by: user.id, created_by_name: user.name }));
        if (!error) await logActivity(user, 'retur', `Retur EXPIRED/RUSAK ${form.qty} ${p?.unit} ${p?.name} dari ${outletName} — ${form.reason}`);

      } else if (returKondisi === 'repakai' && returAction === 'same') {
        // Bisa dipakai, ukuran sama — adds to stock normally
        ({ error } = await supabase.from('returns').insert({ id: uid(), product_id: form.product_id, qty: Number(form.qty), notes: form.notes, date: form.date, outlet_id: form.outlet_id || null, reason: form.reason, return_type: 'retur_outlet', created_by: user.id, created_by_name: user.name }));
        if (!error) await logActivity(user, 'retur', `Retur ${form.qty} ${p?.unit} ${p?.name} dari ${outletName} — masuk stok kembali`);

      } else if (returKondisi === 'repakai' && returAction === 'convert') {
        // Konversi ke ukuran lebih kecil
        const targetProduct = products.find(x => x.id === convertTargetId);
        const convTargets = getConversionTargets(p);
        const targetInfo = convTargets.find(t => t.product.id === convertTargetId);
        const finalQty = targetInfo?.isAuto ? Number(form.qty) * targetInfo.ratio : Number(convertQty);

        if (!finalQty || finalQty <= 0) { setSaving(false); return showToast('❌ Qty konversi tidak valid'); }

        // Save retur as 'konversi' — does NOT add original to stock
        ({ error } = await supabase.from('returns').insert({ id: uid(), product_id: form.product_id, qty: Number(form.qty), notes: `Dikonversi → ${targetProduct?.name} (${finalQty} ${targetProduct?.unit}). ${form.notes}`.trim(), date: form.date, outlet_id: form.outlet_id || null, reason: form.reason, return_type: 'konversi', created_by: user.id, created_by_name: user.name }));

        // Add stock_in for the converted product
        if (!error) {
          ({ error } = await supabase.from('stock_in').insert({ id: uid(), product_id: convertTargetId, qty: finalQty, notes: `Hasil konversi retur dari ${outletName} (${p?.name} × ${form.qty})`, date: form.date, batch_code: 'KONVERSI-' + today().replace(/-/g,''), created_by: user.id, created_by_name: user.name }));
          if (!error) await logActivity(user, 'retur_konversi', `Retur ${form.qty} ${p?.unit} ${p?.name} dari ${outletName} → dikonversi ke ${finalQty} ${targetProduct?.unit} ${targetProduct?.name}`);
        }
      }
    }
    setSaving(false);
    if (error) return showToast('❌ Gagal: ' + error.message);
    showToast('✅ ' + tabLabel[activeTab] + ' berhasil disimpan');
    resetForm();
    onRefresh();
  };

  const handleKonversi = async () => {
    if (!konvSrcId || !konvQty || Number(konvQty) <= 0) return showToast('❌ Pilih produk asal & masukkan qty');
    if (!konvTargetId) return showToast('❌ Pilih ukuran tujuan konversi');
    const srcProduct = products.find(p => p.id === konvSrcId);
    const convTargets = getConversionTargets(srcProduct);
    const targetInfo = convTargets.find(t => t.product.id === konvTargetId);
    const finalQty = targetInfo?.isAuto ? Number(konvQty) * targetInfo.ratio : Number(konvManualQty);
    if (!finalQty || finalQty <= 0) return showToast('❌ Qty hasil konversi tidak valid');
    if (Number(konvQty) > (currentStock[konvSrcId]||0)) return showToast(`❌ Stok tidak cukup (tersedia: ${currentStock[konvSrcId]||0} ${srcProduct?.unit})`);
    setSaving(true);
    const targetProduct = products.find(p => p.id === konvTargetId);
    const { error: e1 } = await supabase.from('stock_out').insert({
      id: uid(), product_id: konvSrcId, qty: Number(konvQty),
      notes: `Dikonversi → ${targetProduct?.name} (${finalQty} ${targetProduct?.unit}). ${konvNotes}`.trim(),
      date: konvDate, reason: `Konversi ke ${targetProduct?.name}`, out_type: 'konversi',
      created_by: user.id, created_by_name: user.name
    });
    if (e1) { setSaving(false); return showToast('❌ ' + e1.message); }
    const { error: e2 } = await supabase.from('stock_in').insert({
      id: uid(), product_id: konvTargetId, qty: finalQty,
      notes: `Hasil konversi dari ${srcProduct?.name} × ${konvQty}. ${konvNotes}`.trim(),
      date: konvDate, batch_code: 'KONVERSI-' + konvDate.replace(/-/g,''),
      created_by: user.id, created_by_name: user.name
    });
    if (e2) { setSaving(false); return showToast('❌ ' + e2.message); }
    await logActivity(user, 'konversi_stok', `Konversi ${konvQty} ${srcProduct?.unit} ${srcProduct?.name} → ${finalQty} ${targetProduct?.unit} ${targetProduct?.name}`);
    showToast(`✅ ${konvQty} ${srcProduct?.unit} ${srcProduct?.name} → ${finalQty} ${targetProduct?.unit} ${targetProduct?.name}`);
    setSaving(false);
    setKonvKat(''); setKonvVariant(''); setKonvSrcId(''); setKonvQty(''); setKonvTargetId(''); setKonvManualQty(''); setKonvNotes(''); setKonvDate(today());
    onRefresh();
  };

  const activeData = activeTab === 'in' ? stockIn
    : activeTab === 'out' ? stockOut.filter(x => x.out_type !== 'konversi')
    : activeTab === 'konversi' ? stockOut.filter(x => x.out_type === 'konversi')
    : returns;

  // Stock summary per product
  const stockSummary = products.map(p => {
    const totalIn    = stockIn.filter(x => x.product_id === p.id).reduce((s,x) => s + Number(x.qty), 0);
    const totalOut   = stockOut.filter(x => x.product_id === p.id).reduce((s,x) => s + Number(x.qty), 0);
    const totalRetur = returns.filter(x => x.product_id === p.id).reduce((s,x) => s + Number(x.qty), 0);
    const orderOut   = 0; // handled in currentStock
    return { ...p, totalIn, totalOut, totalRetur, saldo: currentStock[p.id] || 0 };
  });

  return (
    <div>
      <h2 style={{ margin:'0 0 20px', fontWeight:800, color:'#1a1a2e' }}>Manajemen Stok</h2>

      {/* Stock Summary */}
      <div style={{ background:'#fff', borderRadius:12, padding:20, boxShadow:'0 1px 4px rgba(0,0,0,.07)', marginBottom:20 }}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12, flexWrap:'wrap', gap:8 }}>
          <h3 style={{ margin:0, fontSize:14, fontWeight:700 }}>📊 Ringkasan Stok</h3>
          <label style={{ fontSize:12, color:'#64748b', display:'flex', alignItems:'center', gap:6, cursor:'pointer' }}>
            <input type="checkbox" checked={onlyHasStock} onChange={e => setOnlyHasStock(e.target.checked)} />
            Tampilkan yang ada stok saja
          </label>
        </div>

        {/* Category filter chips */}
        <div style={{ display:'flex', gap:6, marginBottom:12, flexWrap:'wrap' }}>
          {['all', ...KAT_LIST].map(k => {
            const count = k === 'all' ? stockSummary.length : stockSummary.filter(p => p.kategori === k).length;
            return (
              <button key={k} onClick={() => setSummaryKat(k)}
                style={{ padding:'5px 12px', fontSize:11, fontWeight:600, border:'none', borderRadius:20, cursor:'pointer',
                  background: summaryKat===k ? '#1a1a2e' : '#e2e8f0', color: summaryKat===k ? '#fff' : '#64748b' }}>
                {k === 'all' ? 'Semua' : k} ({count})
              </button>
            );
          })}
          <input value={summarySearch} onChange={e => setSummarySearch(e.target.value)}
            placeholder="🔍 Cari produk..."
            style={{ padding:'5px 12px', borderRadius:20, border:'1px solid #e2e8f0', fontSize:12, marginLeft:'auto', minWidth:160 }} />
        </div>

        {/* Table */}
        <div style={{ overflowX:'auto' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:13 }}>
            <thead><tr style={{ background:'#f8f7f4' }}>
              {['Produk','Masuk','Retur','Keluar','→ Outlet','SALDO','Min'].map((h,i) => (
                <th key={i} style={{ padding:'8px 10px', textAlign: i > 0 ? 'right' : 'left', fontSize:11, color:'#64748b', fontWeight:700, borderBottom:'2px solid #e2e8f0' }}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {(() => {
                const filtered = stockSummary
                  .filter(p => summaryKat === 'all' || p.kategori === summaryKat)
                  .filter(p => !summarySearch || p.name.toLowerCase().includes(summarySearch.toLowerCase()))
                  .filter(p => !onlyHasStock || p.saldo > 0 || p.totalIn > 0);

                if (filtered.length === 0) return (
                  <tr><td colSpan={7} style={{ textAlign:'center', padding:24, color:'#94a3b8' }}>Tidak ada data</td></tr>
                );

                // Group by kategori when showing all
                const groups = {};
                filtered.forEach(p => {
                  const k = p.kategori || 'Lainnya';
                  if (!groups[k]) groups[k] = [];
                  groups[k].push(p);
                });
                const KAT_COLOR = { 'Lapis Legit':'#fef3c7','Lapis Surabaya':'#dbeafe','Cookies':'#fce7f3','Gift Box':'#d1fae5' };
                const rows = [];
                Object.entries(groups).forEach(([kat, items]) => {
                  if (summaryKat === 'all') {
                    rows.push(
                      <tr key={'hdr-'+kat}>
                        <td colSpan={7} style={{ padding:'6px 10px', background: KAT_COLOR[kat]||'#f1f5f9', fontSize:12, fontWeight:700, color:'#374151' }}>
                          🏷 {kat} — {items.length} produk
                        </td>
                      </tr>
                    );
                  }
                  items.forEach(p => {
                    const orderOut = p.totalIn + p.totalRetur - p.saldo - p.totalOut;
                    const isLow = p.saldo > 0 && p.saldo <= (p.stok_minimum||5);
                    const isEmpty = p.saldo <= 0;
                    const dispName = p.name.includes(' - ') ? p.name : p.name;
                    rows.push(
                      <tr key={p.id} style={{ borderBottom:'1px solid #f1f5f9', background: isEmpty && p.totalIn > 0 ? '#fff5f5' : isLow ? '#fffbeb' : '' }}>
                        <td style={{ padding:'8px 10px', fontWeight:600, fontSize:12 }}>{dispName}</td>
                        <td style={{ padding:'8px 10px', textAlign:'right', color:'#10b981', fontWeight:600 }}>+{p.totalIn}</td>
                        <td style={{ padding:'8px 10px', textAlign:'right', color:'#f59e0b', fontWeight:600 }}>+{p.totalRetur}</td>
                        <td style={{ padding:'8px 10px', textAlign:'right', color:'#ef4444', fontWeight:600 }}>-{p.totalOut}</td>
                        <td style={{ padding:'8px 10px', textAlign:'right', color:'#8b5cf6', fontWeight:600 }}>-{Math.max(0,orderOut)}</td>
                        <td style={{ padding:'8px 10px', textAlign:'right', fontWeight:800, fontSize:14, color: isEmpty && p.totalIn > 0 ? '#ef4444' : isLow ? '#f59e0b' : '#1a1a2e' }}>{p.saldo}</td>
                        <td style={{ padding:'8px 10px', textAlign:'right', fontSize:11, color:'#94a3b8' }}>{p.stok_minimum||5}</td>
                      </tr>
                    );
                  });
                });
                return rows;
              })()}
            </tbody>
          </table>
        </div>
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'360px 1fr', gap:20 }}>
        {/* Form */}
        {canEdit && (
          <div style={{ background:'#fff', borderRadius:12, padding:20, boxShadow:'0 1px 4px rgba(0,0,0,.07)', height:'fit-content' }}>
            <div style={{ display:'flex', gap:4, marginBottom:20, flexWrap:'wrap' }}>
              {['in','out','retur','konversi'].map(t => (
                <button key={t} onClick={() => { setActiveTab(t); resetForm(); }} style={{ flex:1, padding:'8px 4px', fontSize:10, fontWeight:700, background: activeTab===t ? tabColor[t] : '#f1f5f9', color: activeTab===t ? '#fff' : '#64748b', border:'none', borderRadius:8, cursor:'pointer', minWidth:60 }}>{tabLabel[t]}</button>
              ))}
            </div>

            {/* ── KONVERSI STOK FORM ── */}
            {activeTab === 'konversi' && (() => {
              const srcProd    = products.find(p => p.id === konvSrcId);
              const convTargets = getConversionTargets(srcProd);
              const selTarget  = convTargets.find(t => t.product.id === konvTargetId);
              const autoQty    = selTarget?.isAuto && konvQty ? Number(konvQty) * selTarget.ratio : null;
              const stokAsal   = currentStock[konvSrcId] || 0;
              const kurang     = konvQty && Number(konvQty) > stokAsal;
              return (
                <>
                  <FieldGroup label="Tanggal">
                    <input type="date" value={konvDate} onChange={e => setKonvDate(e.target.value)} style={S.input} />
                  </FieldGroup>

                  <div style={{ marginTop:12 }}>
                    <div style={{ fontSize:12, fontWeight:700, color:'#6d28d9', marginBottom:10 }}>✂️ Produk Asal (yang dipotong)</div>
                    <FieldGroup label="Kategori">
                      <select value={konvKat} onChange={e => { setKonvKat(e.target.value); setKonvVariant(''); setKonvSrcId(''); setKonvTargetId(''); setKonvManualQty(''); }} style={S.input}>
                        <option value=''>-- Semua Kategori --</option>
                        {KAT_LIST.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                    </FieldGroup>
                  </div>
                  <div style={{ marginTop:10 }}>
                    <FieldGroup label="Varian">
                      <select value={konvVariant} onChange={e => { setKonvVariant(e.target.value); setKonvSrcId(''); setKonvTargetId(''); setKonvManualQty(''); }} style={S.input}>
                        <option value=''>-- Pilih Varian --</option>
                        {variantsFor(konvKat).map(v => <option key={v} value={v}>{v}</option>)}
                      </select>
                    </FieldGroup>
                  </div>
                  {konvVariant && (
                    <div style={{ marginTop:10 }}>
                      <FieldGroup label="Ukuran Asal">
                        <select value={konvSrcId} onChange={e => { setKonvSrcId(e.target.value); setKonvTargetId(''); setKonvManualQty(''); }} style={S.input}>
                          <option value=''>-- Pilih Ukuran --</option>
                          {sizesFor(konvVariant).map(p => {
                            const size = p.name.replace(konvVariant, '').replace(/^\s*-\s*/, '').trim() || 'Standard';
                            const targets = getConversionTargets(p);
                            return (
                              <option key={p.id} value={p.id} disabled={targets.length === 0}>
                                {size} — Stok: {currentStock[p.id]||0} {p.unit}{targets.length === 0 ? ' (tidak bisa dikonversi)' : ''}
                              </option>
                            );
                          })}
                        </select>
                      </FieldGroup>
                    </div>
                  )}

                  {konvSrcId && (
                    <div style={{ marginTop:10 }}>
                      <FieldGroup label="Qty yang Dikonversi">
                        <input type="number" min="1" max={stokAsal} value={konvQty}
                          onChange={e => { setKonvQty(e.target.value); setKonvManualQty(''); }}
                          style={{ ...S.input, borderColor: kurang ? '#ef4444' : undefined }} placeholder="0" />
                        {kurang && <div style={{ fontSize:11, color:'#ef4444', marginTop:4 }}>⚠️ Stok tersedia hanya {stokAsal} {srcProd?.unit}</div>}
                        {!kurang && konvQty && <div style={{ fontSize:11, color:'#10b981', marginTop:4 }}>✓ Sisa stok setelah konversi: {stokAsal - Number(konvQty)} {srcProd?.unit}</div>}
                      </FieldGroup>
                    </div>
                  )}

                  {konvSrcId && convTargets.length > 0 && (
                    <div style={{ marginTop:14, padding:12, background:'#f5f3ff', borderRadius:10, border:'1px solid #ddd6fe' }}>
                      <div style={{ fontSize:12, fontWeight:700, color:'#6d28d9', marginBottom:10 }}>Konversi ke Ukuran</div>
                      <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
                        {convTargets.map(t => {
                          const previewQty = t.isAuto && konvQty ? Number(konvQty) * t.ratio : null;
                          const isSelected = konvTargetId === t.product.id;
                          return (
                            <button key={t.product.id} onClick={() => { setKonvTargetId(t.product.id); setKonvManualQty(''); }}
                              style={{ flex:1, padding:'10px 8px', borderRadius:10, border:`2px solid ${isSelected ? '#8b5cf6' : '#e2e8f0'}`, cursor:'pointer', textAlign:'center', fontSize:12, fontWeight:700, background: isSelected ? '#ede9fe' : '#fff', color: isSelected ? '#6d28d9' : '#64748b' }}>
                              <div>{t.label}</div>
                              {t.isAuto && previewQty && <div style={{ fontSize:10, fontWeight:400, marginTop:2 }}>= {previewQty} {t.product.unit}</div>}
                              {!t.isAuto && <div style={{ fontSize:10, fontWeight:400, marginTop:2 }}>qty manual</div>}
                            </button>
                          );
                        })}
                      </div>

                      {konvTargetId && selTarget && (
                        <div style={{ marginTop:12 }}>
                          {selTarget.isAuto && autoQty ? (
                            <div style={{ padding:'10px 12px', background:'#dbeafe', borderRadius:8, fontSize:13, color:'#1e40af', fontWeight:700 }}>
                              📐 {konvQty} {srcProd?.unit} → {autoQty} {selTarget.product.unit} {selTarget.label}
                            </div>
                          ) : (
                            <FieldGroup label={`Qty Hasil (${selTarget.label})`}>
                              <input type="number" min="1" value={konvManualQty} onChange={e => setKonvManualQty(e.target.value)} style={S.input} placeholder={`Masukkan jumlah ${selTarget.label} hasil potongan`} />
                            </FieldGroup>
                          )}
                        </div>
                      )}
                    </div>
                  )}

                  {konvSrcId && convTargets.length === 0 && (
                    <div style={{ marginTop:10, padding:'10px 12px', background:'#fee2e2', borderRadius:8, fontSize:12, color:'#991b1b' }}>
                      ❌ Ukuran ini tidak bisa dikonversi ke ukuran lain.
                    </div>
                  )}

                  <div style={{ marginTop:12 }}>
                    <FieldGroup label="Catatan (opsional)">
                      <input value={konvNotes} onChange={e => setKonvNotes(e.target.value)} style={S.input} placeholder="Misal: sisa order, stok berlebih, dll..." />
                    </FieldGroup>
                  </div>

                  <Btn onClick={handleKonversi} disabled={saving || !konvSrcId || !konvQty || !konvTargetId || kurang} color="#8b5cf6" style={{ marginTop:16, width:'100%' }}>
                    {saving ? 'Menyimpan...' : '✂️ Konversi Stok'}
                  </Btn>
                </>
              );
            })()}

            {/* ── IN / OUT / RETUR FORM (hidden when konversi tab active) ── */}
            {activeTab !== 'konversi' && <>

            {/* 1. TANGGAL — always first */}
            <FieldGroup label="Tanggal">
              <input type="date" value={form.date} onChange={e => setForm(f => ({...f, date: e.target.value}))} style={S.input} />
            </FieldGroup>

            {/* 2. DARI OUTLET — retur only, before product */}
            {activeTab === 'retur' && (
              <div style={{ marginTop:12 }}>
                <FieldGroup label="Dari Outlet">
                  <select value={form.outlet_id} onChange={e => setForm(f => ({...f, outlet_id: e.target.value}))} style={S.input}>
                    <option value=''>-- Pilih Outlet --</option>
                    {outlets.map(o => <option key={o.id} value={o.id}>{o.name}</option>)}
                  </select>
                </FieldGroup>
              </div>
            )}

            {/* 3. PRODUK — Kategori → Varian → Ukuran */}
            <div style={{ marginTop:12 }}>
              <FieldGroup label="Kategori Produk">
                <select value={formKat} onChange={e => { setFormKat(e.target.value); setFormVariant(''); setForm(f => ({...f, product_id:''})); setConvertTargetId(''); setConvertQty(''); }} style={S.input}>
                  <option value=''>-- Semua Kategori --</option>
                  {KAT_LIST.map(k => <option key={k} value={k}>{k}</option>)}
                </select>
              </FieldGroup>
            </div>
            <div style={{ marginTop:10 }}>
              <FieldGroup label="Varian">
                <select value={formVariant} onChange={e => { setFormVariant(e.target.value); setForm(f => ({...f, product_id:''})); setConvertTargetId(''); setConvertQty(''); }} style={S.input}>
                  <option value=''>-- Pilih Varian --</option>
                  {variantsFor(formKat).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </FieldGroup>
            </div>
            {formVariant && (
              <div style={{ marginTop:10 }}>
                <FieldGroup label="Ukuran">
                  <select value={form.product_id} onChange={e => { setForm(f => ({...f, product_id: e.target.value})); setConvertTargetId(''); setConvertQty(''); }} style={S.input}>
                    <option value=''>-- Pilih Ukuran --</option>
                    {sizesFor(formVariant).map(p => {
                      const sizePart = p.name.replace(formVariant, '').replace(/^\s*-\s*/, '').trim() || 'Standard';
                      return <option key={p.id} value={p.id}>{sizePart} (Stok: {currentStock[p.id]||0} {p.unit})</option>;
                    })}
                  </select>
                </FieldGroup>
              </div>
            )}

            {/* 4. JUMLAH — right after product */}
            <div style={{ marginTop:12 }}>
              <FieldGroup label="Jumlah">
                <input type="number" min="1" value={form.qty} onChange={e => setForm(f => ({...f, qty: e.target.value}))} style={S.input} placeholder="0" />
              </FieldGroup>
            </div>

            {/* 5a. Stok Masuk extras: Kode Batch + Expired */}
            {activeTab === 'in' && <>
              <div style={{ marginTop:12 }}>
                <FieldGroup label="Kode Batch *">
                  <input value={form.batch_code} onChange={e => setForm(f => ({...f, batch_code: e.target.value}))} style={S.input} placeholder="Contoh: LP-001, PANDAN-18JUNI" />
                </FieldGroup>
              </div>
              <div style={{ marginTop:12 }}>
                <FieldGroup label="Tanggal Expired (opsional)">
                  <input type="date" value={form.expired_date} onChange={e => setForm(f => ({...f, expired_date: e.target.value}))} style={S.input} />
                </FieldGroup>
              </div>
            </>}

            {/* 5b. Keluar/Defect extras: Jenis + Alasan */}
            {activeTab === 'out' && <>
              <div style={{ marginTop:12 }}>
                <FieldGroup label="Jenis Keluar">
                  <select value={form.out_type} onChange={e => setForm(f => ({...f, out_type: e.target.value}))} style={S.input}>
                    <option value="manual_defect">Rusak/Defect di Gudang</option>
                    <option value="sample">Sample/Tester</option>
                    <option value="other">Lainnya</option>
                  </select>
                </FieldGroup>
              </div>
              <div style={{ marginTop:12 }}>
                <FieldGroup label="Alasan *">
                  <select value={form.reason} onChange={e => setForm(f => ({...f, reason: e.target.value}))} style={S.input}>
                    <option value=''>-- Pilih alasan --</option>
                    {DEFECT_REASONS.map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
                </FieldGroup>
              </div>
            </>}

            {/* 5c. Retur extras: Kondisi → Tindakan → Konversi → Alasan */}
            {activeTab === 'retur' && <>
              {/* Kondisi barang */}
              <div style={{ marginTop:14 }}>
                <div style={{ fontSize:12, fontWeight:700, color:'#374151', marginBottom:8 }}>Kondisi Barang *</div>
                <div style={{ display:'flex', gap:8 }}>
                  {[
                    { val:'rusak',   icon:'🔴', label:'Expired / Rusak',      sub:'Tidak bisa dipakai kembali',  activeColor:'#ef4444', activeBg:'#fee2e2' },
                    { val:'repakai', icon:'🟢', label:'Bisa Dipakai Kembali', sub:'Kembali ke stok produksi',   activeColor:'#10b981', activeBg:'#dcfce7' },
                  ].map(opt => (
                    <button key={opt.val} onClick={() => { setReturKondisi(opt.val); setReturAction(''); setConvertTargetId(''); setConvertQty(''); }}
                      style={{ flex:1, padding:'10px 8px', borderRadius:10, border:`2px solid ${returKondisi === opt.val ? opt.activeColor : '#e2e8f0'}`, cursor:'pointer', textAlign:'center', fontSize:12, fontWeight:700, background: returKondisi === opt.val ? opt.activeBg : '#fff', color: returKondisi === opt.val ? opt.activeColor : '#64748b', transition:'all .15s' }}>
                      <div>{opt.icon} {opt.label}</div>
                      <div style={{ fontSize:10, fontWeight:400, marginTop:3, opacity:.8 }}>{opt.sub}</div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Tindakan — only if bisa dipakai */}
              {returKondisi === 'repakai' && (() => {
                const srcProd = products.find(x => x.id === form.product_id);
                const convTargets = getConversionTargets(srcProd);
                return (
                  <div style={{ marginTop:12 }}>
                    <div style={{ fontSize:12, fontWeight:700, color:'#374151', marginBottom:8 }}>Tindakan *</div>
                    <div style={{ display:'flex', gap:8 }}>
                      <button onClick={() => { setReturAction('same'); setConvertTargetId(''); setConvertQty(''); }}
                        style={{ flex:1, padding:'9px 8px', borderRadius:10, border:`2px solid ${returAction==='same' ? '#3b82f6' : '#e2e8f0'}`, cursor:'pointer', fontSize:12, fontWeight:700, background: returAction==='same' ? '#eff6ff' : '#fff', color: returAction==='same' ? '#1d4ed8' : '#64748b' }}>
                        📦 Simpan Ukuran Sama
                      </button>
                      {convTargets.length > 0 && (
                        <button onClick={() => setReturAction('convert')}
                          style={{ flex:1, padding:'9px 8px', borderRadius:10, border:`2px solid ${returAction==='convert' ? '#8b5cf6' : '#e2e8f0'}`, cursor:'pointer', fontSize:12, fontWeight:700, background: returAction==='convert' ? '#f5f3ff' : '#fff', color: returAction==='convert' ? '#6d28d9' : '#64748b' }}>
                          ✂️ Konversi Ukuran
                        </button>
                      )}
                    </div>
                  </div>
                );
              })()}

              {/* Konversi detail */}
              {returKondisi === 'repakai' && returAction === 'convert' && (() => {
                const srcProd = products.find(x => x.id === form.product_id);
                const convTargets = getConversionTargets(srcProd);
                const selTarget = convTargets.find(t => t.product.id === convertTargetId);
                const autoQty = selTarget?.isAuto && form.qty ? Number(form.qty) * selTarget.ratio : null;
                return (
                  <div style={{ marginTop:12, padding:'14px', background:'#f5f3ff', borderRadius:10, border:'1px solid #ddd6fe' }}>
                    <div style={{ fontSize:12, fontWeight:700, color:'#6d28d9', marginBottom:10 }}>✂️ Detail Konversi</div>
                    <FieldGroup label="Konversi ke Ukuran">
                      <select value={convertTargetId} onChange={e => { setConvertTargetId(e.target.value); setConvertQty(''); }} style={S.input}>
                        <option value=''>-- Pilih ukuran tujuan --</option>
                        {convTargets.map(t => (
                          <option key={t.product.id} value={t.product.id}>
                            {t.label} {t.isAuto ? `(otomatis: ${form.qty ? Number(form.qty)*t.ratio : '?'} ${t.product.unit})` : `(qty manual)`}
                          </option>
                        ))}
                      </select>
                    </FieldGroup>
                    {convertTargetId && selTarget && (
                      <div style={{ marginTop:10 }}>
                        {selTarget.isAuto ? (
                          <div style={{ padding:'10px 12px', background:'#dbeafe', borderRadius:8, fontSize:13, color:'#1e40af', fontWeight:600 }}>
                            📐 {form.qty||'?'} {srcProd?.unit} {getSizeName(srcProd?.name||'')} → {autoQty} {selTarget.product.unit} {selTarget.label}
                          </div>
                        ) : (
                          <FieldGroup label={`Qty Hasil (${selTarget.label})`}>
                            <input type="number" min="1" value={convertQty} onChange={e => setConvertQty(e.target.value)} style={S.input} placeholder={`Masukkan jumlah ${selTarget.label} hasil potongan`} />
                          </FieldGroup>
                        )}
                      </div>
                    )}
                  </div>
                );
              })()}

              {/* Alasan retur */}
              <div style={{ marginTop:12 }}>
                <FieldGroup label="Alasan Retur *">
                  <select value={form.reason} onChange={e => setForm(f => ({...f, reason: e.target.value}))} style={S.input}>
                    <option value=''>-- Pilih alasan --</option>
                    {RETUR_REASONS.map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
                </FieldGroup>
              </div>
            </>}

            {/* CATATAN — always last */}
            <div style={{ marginTop:12 }}>
              <FieldGroup label="Catatan">
                <input value={form.notes} onChange={e => setForm(f => ({...f, notes: e.target.value}))} style={S.input} placeholder="Opsional..." />
              </FieldGroup>
            </div>

            <Btn onClick={handleAdd} disabled={saving} color={tabColor[activeTab]} style={{ marginTop:16, width:'100%' }}>
              {saving ? 'Menyimpan...' : `+ Tambah ${tabLabel[activeTab]}`}
            </Btn>

            </> /* end activeTab !== 'konversi' */}
          </div>
        )}

        {/* History */}
        <div style={{ background:'#fff', borderRadius:12, padding:20, boxShadow:'0 1px 4px rgba(0,0,0,.07)' }}>
          <div style={{ display:'flex', gap:4, marginBottom:16, flexWrap:'wrap' }}>
            {['in','out','retur','konversi'].map(t => {
              const count = t==='in' ? stockIn.length : t==='out' ? stockOut.filter(x => x.out_type !== 'konversi').length : t==='retur' ? returns.length : stockOut.filter(x => x.out_type === 'konversi').length;
              return <button key={t} onClick={() => setActiveTab(t)} style={{ padding:'7px 12px', fontSize:10, fontWeight:700, background: activeTab===t ? tabColor[t] : '#f1f5f9', color: activeTab===t ? '#fff' : '#64748b', border:'none', borderRadius:8, cursor:'pointer' }}>{tabLabel[t]} ({count})</button>;
            })}
          </div>
          <div style={{ overflowX:'auto' }}>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:13 }}>
              <thead><tr style={{ background:'#f8f7f4' }}>
                <th style={{ padding:'10px 12px', textAlign:'left', fontSize:11, color:'#64748b', fontWeight:700, borderBottom:'2px solid #e2e8f0' }}>Tanggal</th>
                <th style={{ padding:'10px 12px', textAlign:'left', fontSize:11, color:'#64748b', fontWeight:700, borderBottom:'2px solid #e2e8f0' }}>Produk</th>
                {activeTab === 'in' && <th style={{ padding:'10px 12px', textAlign:'left', fontSize:11, color:'#64748b', fontWeight:700, borderBottom:'2px solid #e2e8f0' }}>Batch</th>}
                {activeTab === 'out' && <th style={{ padding:'10px 12px', textAlign:'left', fontSize:11, color:'#64748b', fontWeight:700, borderBottom:'2px solid #e2e8f0' }}>Alasan</th>}
                {activeTab === 'retur' && <th style={{ padding:'10px 12px', textAlign:'left', fontSize:11, color:'#64748b', fontWeight:700, borderBottom:'2px solid #e2e8f0' }}>Alasan</th>}
                <th style={{ padding:'10px 12px', textAlign:'right', fontSize:11, color:'#64748b', fontWeight:700, borderBottom:'2px solid #e2e8f0' }}>Qty</th>
                <th style={{ padding:'10px 12px', textAlign:'left', fontSize:11, color:'#64748b', fontWeight:700, borderBottom:'2px solid #e2e8f0' }}>Oleh</th>
              </tr></thead>
              <tbody>
                {activeData.length === 0
                  ? <tr><td colSpan={6} style={{ textAlign:'center', padding:32, color:'#94a3b8' }}>Belum ada data</td></tr>
                  : activeData.map(x => {
                    const p = products.find(pp => pp.id === x.product_id);
                    return (
                      <tr key={x.id} style={{ borderBottom:'1px solid #f1f5f9' }}>
                        <td style={{ padding:'10px 12px', fontSize:13 }}>{fmtDate(x.date)}</td>
                        <td style={{ padding:'10px 12px', fontSize:13 }}>{p?.name||'-'}</td>
                        {activeTab === 'in' && <td style={{ padding:'10px 12px', fontSize:12 }}><span style={{ background:'#dbeafe', color:'#1e40af', padding:'2px 8px', borderRadius:6, fontWeight:600 }}>{x.batch_code||'-'}</span></td>}
                        {activeTab !== 'in' && <td style={{ padding:'10px 12px', fontSize:12, color:'#64748b' }}>{x.reason||'-'}</td>}
                        <td style={{ padding:'10px 12px', textAlign:'right', fontWeight:700, color: tabColor[activeTab] }}>{x.qty} {p?.unit}</td>
                        <td style={{ padding:'10px 12px', fontSize:12, color:'#64748b' }}>{x.created_by_name||'-'}</td>
                      </tr>
                    );
                  })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}
